#include<bits/stdc++.h>
using namespace std;
const long long mod=1e9+7;
long long s1[1000010],s2[1000010],s3[1000010],n,t;
long long lowbit(long long x)
{
    return x&-x;
}
long long getsum(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=s1[i]*(x+2)*(x+1)-s2[i]*(x*2+3)+s3[i];
    }
    return ans/2;
}
void add(long long x,long long v)
{
    for(long long i=x;i<=n*2+1;i+=lowbit(i))
    {
        s1[i]+=v;
        s2[i]+=v*x;
        s3[i]+=v*x*x;
    }
}
long long a[1000010];
vector<long long> b[1000010];
int main()
{
    scanf("%lld%lld",&n,&t);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[a[i]].push_back(i);
    }
    long long tmp=n+1,ans=0;
    for(long long i=0;i<n;i++)
    {
        b[i].push_back(n+1);
        long long lst=0;
        for(long long j=0;j<b[i].size();j++)
        {
            long long x=j*2-(b[i][j]-1)+tmp,y=j*2-lst+tmp;
            ans+=getsum(y-1)-(x<3?0:getsum(x-2));
            add(x,1);
            add(y+1,-1);
            lst=b[i][j];
        }
        lst=0;
        for(long long j=0;j<b[i].size();j++)
        {
            long long x=j*2-(b[i][j]-1)+tmp,y=j*2-lst+tmp;
            add(x,-1);
            add(y+1,1);
            lst=b[i][j];
        }
    }
    printf("%lld",ans);
    return 0;
}
